// Construire les URLs de recherche à partir du profil jeune
const jeuneResults = $('📋 Charger profil jeune').all();
const jeune = jeuneResults.length > 0 ? jeuneResults[0].json : {};
const token = $('🔐 Token France Travail').first().json.access_token;

const dept = (jeune.departement || '75').trim();
const romes = (jeune.codes_rome_suggeres || 'M1805').trim();

const deptCoords = {
  '75': { lat: 48.8566, lon: 2.3522 },
  '77': { lat: 48.5272, lon: 2.6987 },
  '78': { lat: 48.8014, lon: 2.1301 },
  '91': { lat: 48.6293, lon: 2.4396 },
  '92': { lat: 48.8283, lon: 2.2399 },
  '93': { lat: 48.9100, lon: 2.4200 },
  '94': { lat: 48.7904, lon: 2.4753 },
  '95': { lat: 49.0354, lon: 2.0733 },
  '69': { lat: 45.7640, lon: 4.8357 },
  '13': { lat: 43.2965, lon: 5.3698 },
  '33': { lat: 44.8378, lon: -0.5792 },
  '59': { lat: 50.6292, lon: 3.0573 },
  '44': { lat: 47.2184, lon: -1.5536 },
  '06': { lat: 43.7102, lon: 7.2620 },
  '34': { lat: 43.6110, lon: 3.8767 },
  '35': { lat: 48.1173, lon: -1.6778 }
};
const coords = deptCoords[dept] || deptCoords['75'];

const ft_url = `https://api.francetravail.io/partenaire/offresdemploi/v2/offres/search?departement=${dept}&distance=20&codeROME=${romes}&range=0-49`;
const lba_url = `https://api.apprentissage.beta.gouv.fr/api/job/v1/search?latitude=${coords.lat}&longitude=${coords.lon}&radius=25&romes=${romes}`;

return [{ json: { token, ft_url, lba_url, dept, romes } }];

// ============================================================================
// 🎯 Formater les résultats pour retour à l'agent
// Le toolWorkflow doit retourner du TEXTE que l'agent peut utiliser
// ============================================================================

const ftData = $('📡 France Travail').first().json;
const lbaData = $('📡 La Bonne Alternance').first().json;

// Offres France Travail
const offresFT = (ftData.resultats || []).slice(0, 10).map((o, i) => {
  const debutant = (o.experienceExige === 'D' || o.experienceExige === 'S') ? 'Débutant accepté' : 'Expérience demandée';
  const url = o.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${o.id}`;
  return `${i+1}. ${o.intitule} | ${o.entreprise?.nom || 'Confidentiel'} | ${o.lieuTravail?.libelle || ''} | ${o.typeContratLibelle || ''} | ${debutant} | ${url}`;
}).join('\n');

// Jobs La Bonne Alternance
const jobsLBA = (lbaData.jobs || []).slice(0, 5).map((j, i) => {
  const url = j.apply?.url || '';
  return `${i+1}. ${j.offer?.title || 'Alternance'} | ${j.workplace?.name || 'Confidentiel'} | ${j.workplace?.location?.city || ''} | Alternance | ${url}`;
}).join('\n');

const nbFT = (ftData.resultats || []).length;
const nbLBA = (lbaData.jobs || []).length;

let result = `RÉSULTATS DE RECHERCHE (${nbFT} offres FT + ${nbLBA} alternances LBA)\n\n`;

if (offresFT) {
  result += `OFFRES D'EMPLOI (France Travail) :\n${offresFT}\n\n`;
}

if (jobsLBA) {
  result += `ALTERNANCES (La Bonne Alternance) :\n${jobsLBA}\n\n`;
}

if (nbFT === 0 && nbLBA === 0) {
  result += `Aucune offre trouvée pour ces critères. Suggère au jeune d'élargir sa zone géographique ou ses secteurs de recherche.`;
} else {
  result += `Présente les 3-5 meilleures offres au jeune de manière naturelle. Privilégie celles qui acceptent les débutants. Inclus les liens pour postuler.`;
}

return [{ json: { response: result } }];
